mapper.select:
SELECT id, lpn_code, pallet_type_id, warehouse_id, location_id, status, gross_weight, deleted, created_at, updated_at, created_by, updated_by FROM lpn WHERE deleted = 0
AND lpn_code LIKE CONCAT('%', #{keyword}, '%')
AND warehouse_id = #{warehouseId}
AND status = #{status}
ORDER BY created_at DESC, id DESC
